import{_ as e,o as s,c as n,ag as t}from"./chunks/framework.BDReElpY.js";const h=JSON.parse('{"title":"Closures and Lambda Expressions","description":"","frontmatter":{},"headers":[],"relativePath":"archive/reference/closures.md","filePath":"archive/reference/closures.md"}'),l={name:"archive/reference/closures.md"};function r(p,a,i,o,c,d){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="closures-and-lambda-expressions" tabindex="-1">Closures and Lambda Expressions <a class="header-anchor" href="#closures-and-lambda-expressions" aria-label="Permalink to &quot;Closures and Lambda Expressions&quot;">​</a></h1><p><strong>Core Language Specification</strong><br><strong>Version:</strong> 0.2.0<br><strong>Status:</strong> ✅ Implemented</p><p>Closures are anonymous functions that can capture their environment. Vex closures are statically typed and zero-cost.</p><hr><h2 id="_1-syntax" tabindex="-1">1. Syntax <a class="header-anchor" href="#_1-syntax" aria-label="Permalink to &quot;1. Syntax&quot;">​</a></h2><p>Vex uses Rust-like pipe syntax for closures.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let add = |a, b| a + b;</span></span>
<span class="line"><span>let square = |x| {</span></span>
<span class="line"><span>    return x * x;</span></span>
<span class="line"><span>};</span></span></code></pre></div><h3 id="type-inference" tabindex="-1">Type Inference <a class="header-anchor" href="#type-inference" aria-label="Permalink to &quot;Type Inference&quot;">​</a></h3><p>Types are usually inferred, but can be explicit.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let mul = |x: i32, y: i32|: i32 {</span></span>
<span class="line"><span>    return x * y;</span></span>
<span class="line"><span>};</span></span></code></pre></div><hr><h2 id="_2-capture-modes" tabindex="-1">2. Capture Modes <a class="header-anchor" href="#_2-capture-modes" aria-label="Permalink to &quot;2. Capture Modes&quot;">​</a></h2><p>Vex automatically determines how variables are captured (Move vs Borrow).</p><ol><li><strong>Borrow (Immutable)</strong>: If captured variable is only read.</li><li><strong>Borrow (Mutable)</strong>: If captured variable is mutated (must be declared <code>let!</code>).</li><li><strong>Move</strong>: If captured variable is consumed (e.g. returned or moved).</li></ol><h3 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! sum = 0;</span></span>
<span class="line"><span>let add_to_sum = |x| {</span></span>
<span class="line"><span>    sum = sum + x; // Mutable capture</span></span>
<span class="line"><span>};</span></span></code></pre></div><hr><h2 id="_3-contracts" tabindex="-1">3. Contracts <a class="header-anchor" href="#_3-contracts" aria-label="Permalink to &quot;3. Contracts&quot;">​</a></h2><p>Closures implement specific contracts based on their capture usage:</p><ul><li><code>contract Callable</code>: Can be called multiple times (Immutable state).</li><li><code>contract CallableMut</code>: Can be called multiple times (Mutable state).</li><li><code>contract CallableOnce</code>: Can be called once (Moves state).</li></ul><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn apply&lt;F: Callable&lt;i32, i32&gt;&gt;(f: F, val: i32): i32 {</span></span>
<span class="line"><span>    return f(val);</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="_4-async-closures-future" tabindex="-1">4. Async Closures (Future) <a class="header-anchor" href="#_4-async-closures-future" aria-label="Permalink to &quot;4. Async Closures (Future)&quot;">​</a></h2><p>Declarative syntax for async closures is planned.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Future Syntax</span></span>
<span class="line"><span>let fetch = async |url| {</span></span>
<span class="line"><span>    let resp = await http.get(url);</span></span>
<span class="line"><span>    return resp;</span></span>
<span class="line"><span>};</span></span></code></pre></div>`,25)])])}const b=e(l,[["render",r]]);export{h as __pageData,b as default};
